import { describe, it, expect } from "vitest";

describe("MHPCO Claim Office", () => {
  // Empty / processing fee
  it.todo("empty item list yields premium of 5 G (processing fee only)");

  // Base premiums for single items (with first insurance + fee, newcomer)
  it.todo("quote for a single plain sword (newcomer, no contracts) yields 115 G (100 base + 10 first + 5 fee)");
  it.todo("quote for a single plain amulet (newcomer) yields 71 G (60 base + 6 first + 5 fee)");
  it.todo("quote for a single plain staff (newcomer) yields 93 G (80 base + 8 first + 5 fee)");
  it.todo("quote for a single plain potion (newcomer) yields 49 G (40 base + 4 first + 5 fee)");

  // Components base premiums
  it.todo("quote for 2 runes yields base premium 50 G (no block applies)");
  it.todo("quote for 3 runes yields base premium 60 G (block of 3 alike applies)");
  it.todo("quote for 4 runes yields base premium 100 G (no block — block requires exactly 3)");
  it.todo("quote for 7 runes yields base premium 175 G (one block of 3 + 4 individual)");

  // "Alike" components — same type
  it.todo("quote for 2 runes + 1 moonstone yields base premium 75 G (no block, different types)");
  it.todo("quote for 3 runes + 3 moonstones yields base premium 120 G (two separate blocks)");

  // Item-specific modifiers
  it.todo("cursed sword adds 50% surcharge to that item's base premium");
  it.todo("sword with enchantment exactly 5 adds 30% high-enchantment surcharge");
  it.todo("sword with enchantment 4 has no high-enchantment surcharge");
  it.todo("cursed sword with enchantment 5 applies both curse and high-enchantment surcharges");

  // Modifier scope on multi-item policies
  it.todo("policy with cursed sword and plain amulet: curse surcharge applies only to sword's base (210 G before policy modifiers + fee)");

  // Policy-wide modifiers
  it.todo("customer with exactly 2 years receives 20% loyalty discount on policy base");
  it.todo("first insurance adds 10% surcharge to policy base");
  it.todo("follow-up contract gives 15% discount on policy base");

  // Processing fee added at the end
  it.todo("5 G processing fee is always added after all other modifiers");

  // Rounding
  it.todo("premium of 197.5 G is rounded UP to 198 G");

  // Integration: Newcomer with cursed sword
  it.todo("newcomer (0 years, no previous) with cursed sword (steel, ench 3) yields premium 165 G");

  // Integration: Long-standing customer's second contract
  it.todo("3-year customer's second contract: cursed sword (steel, ench 7) yields premium 160 G");

  // CLAIM PROCESSING — basic
  it.todo("standard sword damage 500 G yields payout 400 G (500 - 100 deductible)");
  it.todo("rune damage 200 G yields payout 100 G (200 - 100 deductible, no special clauses)");

  // Claim payout rounding
  it.todo("payout of 350.5 G is rounded DOWN to 350 G");

  // Deductible per damage event
  it.todo("dragon attack damages sword (500) and amulet (300): payout 600 G (deductible applies once per item)");

  // Special reimbursement clauses
  it.todo("steel sword with enchantment 9, damage 1000 G: payout 400 G (50% then deductible)");
  it.todo("dragon-material sword with enchantment 5, damage 800 G: payout 700 G (full reimbursement then deductible)");
  it.todo("dragon-material sword with enchantment 9, damage 1000 G: payout 400 G (50% wins, then deductible)");
  it.todo("dragon-material sword with enchantment exactly 8, damage 1000 G: payout 400 G (high-enchantment clause applies)");

  // Cap
  it.todo("sword policy (sum 1000, cap 2000): two claims of 1500 each yield first payout 1400 G with cap 600 remaining");
  it.todo("sword policy second claim of 1500 G with 600 G cap remaining yields payout 600 G and cap 0");
  it.todo("cursed sword: cap is 2000 G based on unmodified insurance value (premium modifiers do not raise cap)");
  it.todo("policy with sword + 3 runes: insurance sum 1750 G (block discount affects only premium, not insurance sum)");

  // Multiple items of same type
  it.todo("policy with two swords: insurance sum 2000 G, cap 4000 G");
  it.todo("two sword damage entries each get their own deductible when both swords are insured");
  it.todo("two sword damage entries when only one sword is insured: claim is rejected");

  // Error cases
  it.todo("quote with unknown item type (e.g. broomstick): exits non-zero with stderr message");
  it.todo("claim referencing item not in policy: exits non-zero with stderr message");
  it.todo("claim with negative damage amount: exits non-zero with stderr message");

  // CLI integration
  it.todo("CLI reads scenario JSON from stdin and writes results JSON to stdout");
  it.todo("CLI processes sequential steps; claim refers to earlier quote by zero-based step index");
});
